/**
 * TravelWell.World — Local & temporal signals (the "knows what's happening"
 * layer behind Atlas + Well Whispers).
 *
 * Same authoring pattern as safety-data.ts: a typed, framework-free module you
 * (David) edit by hand. These curated "Tier A" entries are the offline-first
 * fallback and the seed for the public.local_signals table (migration 0007,
 * generated by scripts/gen-catalog-seed.ts) — so they're served from Postgres
 * and editable without a redeploy, while authored in the repo with review.
 *
 * Honesty contract (mirrors safety-data + Atlas's own rules): never fabricate a
 * dated "happening now." Curate things that are genuinely true and stable —
 * recurring seasons/schedules and well-known annual moments. Volatile "table
 * tonight" data is Tier C (provider-fed), not authored here. Every entry keeps
 * a `source`. `href` should be a real, working one-tap link.
 *
 * Keyed by destinations.id and/or regions.code, tagged by Special Interest and
 * Well so Atlas and the cross-link engine can find what's relevant.
 */

export type SignalKind = "event" | "schedule" | "opening" | "lookahead";
export type SignalHorizon = "now" | "soon" | "lookahead";

export interface LocalSignal {
  id: string;
  kind: SignalKind;
  horizon: SignalHorizon;
  title: string;
  blurb?: string;            // the gentle line, in Atlas's voice
  href?: string;             // real one-tap link (internal guide or external)
  destination?: string;      // destinations.id
  region?: string;           // regions.code
  si?: string[];             // relevant Special Interests
  wells?: string[];          // cross-link engine targets
  season?: string;           // human label, e.g. "Jul–Oct"
  recurrence?: { months?: number[]; days?: number[] }; // months 1-12, days 0-6 (Sun=0)
  startsOn?: string;         // ISO — for genuinely dated events
  endsOn?: string;           // ISO
  validFrom?: string;        // ISO — when to start surfacing
  validTo?: string;          // ISO
  priority?: number;
  source: "curated" | "feed" | "provider";
}

