/** True when a signal's recurring window includes the given month (1-12). */
export function isActiveInMonth(s: LocalSignal, month: number): boolean {
  if (s.recurrence?.months?.length) return s.recurrence.months.includes(month);
  if (s.startsOn && s.endsOn) {
    const m = month;
    const a = new Date(s.startsOn).getMonth() + 1;
    const b = new Date(s.endsOn).getMonth() + 1;
    return a <= b ? m >= a && m <= b : m >= a || m <= b;
  }
  return true; // no temporal bound → always relevant
}

/**
 * Pure relevance filter usable on the bundle or DB rows: keep signals that match
 * the traveler's destination/region, overlap their Special Interests, and (when
 * `month` is given) sort the in-season ones first. Highest priority first.
 */
export function selectSignals(
  all: LocalSignal[],
  q: { destination?: string | null; region?: string | null; si?: string[]; month?: number }
): LocalSignal[] {
  const wantSi = q.si?.length ? new Set(q.si) : null;
  const matched = all.filter((s) => {
    const locOk =
      (!s.destination && !s.region) ||
      (q.destination && s.destination === q.destination) ||
      (q.region && s.region === q.region);
    if (!locOk) return false;
    if (wantSi && s.si?.length && !s.si.some((x) => wantSi.has(x))) return false;
    return true;
  });
  return matched.sort((a, b) => {
    if (q.month != null) {
      const ai = isActiveInMonth(a, q.month) ? 1 : 0;
      const bi = isActiveInMonth(b, q.month) ? 1 : 0;
      if (ai !== bi) return bi - ai;
    }
    return (b.priority ?? 0) - (a.priority ?? 0);
  });
}
